import sailpoint.object.Filter;
    import sailpoint.object.Identity;
    import sailpoint.object.GroupDefinition;
    import sailpoint.object.QueryOptions;
    import sailpoint.tools.Util;

    if (!identity.isInactive()) {
    
        // Get Population
        
        GroupDefinition requestViewers = context.getObjectByName(GroupDefinition.class,"Pop-RequestViewers");
        
        //Construct QueryOptions
        
        QueryOptions ops = new QueryOptions();
        
        //Supply Filter of Population to QueryOptions
        
        ops.addFilter(requestViewers.getFilter());
        
        //Get Objects Matching Supplied Filter
        
        List requestViewersList = context.getObjects(Identity.class, ops);
        
        //Determine if requestViewersList contains passed in Identity
        
        if (Util.nullSafeContains(requestViewersList, identity)) {
        
            //If passed in Identity is in Population (i.e. requestViewersList), assign role
        
            return true;
        
        }

    }
    
    //Do not assign otherwise
    
    return false;
